<td align="left" valign="top" width="90%"><div class="page-content">



                    <!-- start page title -->


                        <div class=" ">
                        <div class="col-md-12 col-xl-12">
						<div style="min-height:500px;">
                            <div class="card-body">
                                    <h4 class="card-title" style=" margin-top:0px; padding-bottom:5px; ">Package Inclusions / Exclusion Setting
                                       </h4>
									        <div style="padding:10px;">
									<div class=" ">
									<form action="frmaction.html" method="post" enctype="multipart/form-data" name="addeditfrm" target="actoinfrm" id="addeditfrm">




									   <div class="card-body">
									   <div class="col-lg-12">
											 <div class="form-group">
											 <label for="validationCustom02">Inclusions Title</label>
                                          <input type="text" class="form-control" id="inclusionsTitle" name="inclusionsTitle" style="padding: 4px;" value="Inclusions &amp; Exclusions">
                                        </div>
										</div>

											<div class="col-lg-12">

											 <div class="form-group">
                                                 <label for="validationCustom02">Inclusions</label>
                                                <textarea name="packageInclusions" id="packageInclusions" style="height: 120px; visibility: hidden; display: none;">&lt;p&gt;&lt;span style="color:#222222"&gt;&lt;strong&gt;Inclusions:&lt;/strong&gt;&nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style="color:rgb(34, 34, 34)"&gt;Room stay on Double sharing basis&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style="color:rgb(34, 34, 34)"&gt;Breakfast on all days except Day 1.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style="color:rgb(34, 34, 34)"&gt;All Tours and Transfers on S.I.C or Private basis as mentioned&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style="color:#222222"&gt;5% GST Included&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style="color:#222222"&gt;5% TCS Included&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style="color:#222222"&gt;Flights Included&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style="color:#222222"&gt;Accomodation Included&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style="color:#222222"&gt;VISA Included&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style="color:#222222"&gt;Activity Entrance Tickets Included.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style="color:#222222"&gt;&lt;strong&gt;Exclusions:&lt;/strong&gt;&nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style="color:#222222"&gt;Any other services or meals which are not mentioned in the above "Includes" section.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style="color:#222222"&gt;Lunch and Dinner unless specified&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style="color:#222222"&gt;Early Check-in/Check-Out (Unless Specified)&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;Island fees directly payable at spot.&lt;/li&gt;
	&lt;li&gt;Tourism Tax Directly Payable At Hotel (If Applicable or Mandatory From Country)&lt;/li&gt;
	&lt;li&gt;&lt;span style="color:#222222"&gt;Expense of personal nature such as mineral water, laundry, telephones, beverages etc.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style="color:#222222"&gt;Any tips to the hotel or tour organisers orr guide&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style="color:rgb(34, 34, 34)"&gt;Camera Charges if any. (Depends upon the Sizes of the Lens)&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;
